wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(11947645433917326)
,p_chart_id=>wwv_flow_imp.id(11945907040917321)
,p_seq=>10
,p_name=>'New'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT TO_CHAR(year_num) AS year_num,',
'       month_name,',
'       ytd_cumulative,',
'       CASE ',
'           WHEN year_num = EXTRACT(YEAR FROM TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD'')) THEN ''#ff2d55'' ',
'           ELSE ''#ffb3c1'' ',
'       END AS color_code',
'FROM (',
'    SELECT',
'        EXTRACT(YEAR FROM flow_date) AS year_num,',
'        EXTRACT(MONTH FROM flow_date) AS month_num,',
'        TO_CHAR(flow_date, ''MM-Mon'') AS month_name,',
'        SUM(newly_identified) OVER (',
'            PARTITION BY EXTRACT(YEAR FROM flow_date)',
'            ORDER BY flow_date',
'        ) AS ytd_cumulative',
'    FROM shelter_system_flow',
'    WHERE population_group = ''All Population''',
'      AND EXTRACT(YEAR FROM flow_date) IN (',
'          EXTRACT(YEAR FROM TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD'')),',
'          EXTRACT(YEAR FROM TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD'')) - 1',
'      )',
'      AND EXTRACT(MONTH FROM flow_date) <=',
'          EXTRACT(MONTH FROM TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD''))',
')',
'ORDER BY year_num, month_num'))
,p_ajax_items_to_submit=>'P2_REPORTING_DATE'
,p_series_name_column_name=>'YEAR_NUM'
,p_items_value_column_name=>'YTD_CUMULATIVE'
,p_items_label_column_name=>'MONTH_NAME'
,p_color=>'&COLOR_CODE.'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>true
,p_items_label_position=>'outsideBarEdge'
);
