'SELECT TO_CHAR(year_num) AS year_num,',
'       month_name,',
'       ytd_cumulative,',
'       -- Logic for Green/Success tones',
'       CASE ',
'           WHEN year_num = EXTRACT(YEAR FROM TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD'')) THEN ''#5ba75b'' -- Darker Green (Current)',
'           ELSE ''#aed5ae'' -- Lighter Green (Previous)',
'       END AS color_code',
'FROM (',
'    SELECT',
'        EXTRACT(YEAR FROM flow_date) AS year_num,',
'        EXTRACT(MONTH FROM flow_date) AS month_num,',
'        TO_CHAR(flow_date, ''MM-Mon'') AS month_name,',
'        SUM(moved_to_housing) OVER (',
'            PARTITION BY EXTRACT(YEAR FROM flow_date)',
'            ORDER BY flow_date',
'        ) AS ytd_cumulative',
'    FROM shelter_system_flow',
'    WHERE population_group = ''All Population''',
'      AND EXTRACT(YEAR FROM flow_date) IN (',
