'          EXTRACT(YEAR FROM TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD'')) - 1',
'      )',
'      AND EXTRACT(MONTH FROM flow_date) <=',
'          EXTRACT(MONTH FROM TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD''))',
')',
'ORDER BY year_num, month_num'))
