wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(161360250705058784094)
,p_chart_id=>wwv_flow_imp.id(161360250596607784093)
,p_seq=>10
,p_name=>'Age band'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT 1 AS sort_order,',
'       ''Under 16'' AS age_band,',
'       age_under_16 / (age_under_16 + age_16_24 + age_25_34 + age_35_44 + age_45_54 + age_55_64 + age_65_over) AS pct',
'FROM shelter_system_flow',
'WHERE flow_date = TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD'')',
'  AND population_group = ''All Population''',
'UNION ALL',
'SELECT 2, ''16-24'',',
'       age_16_24 / (age_under_16 + age_16_24 + age_25_34 + age_35_44 + age_45_54 + age_55_64 + age_65_over)',
'FROM shelter_system_flow',
'WHERE flow_date = TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD'')',
'  AND population_group = ''All Population''',
'UNION ALL',
'SELECT 3, ''25-34'',',
'       age_25_34 / (age_under_16 + age_16_24 + age_25_34 + age_35_44 + age_45_54 + age_55_64 + age_65_over)',
'FROM shelter_system_flow',
'WHERE flow_date = TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD'')',
'  AND population_group = ''All Population''',
'UNION ALL',
'SELECT 4, ''35-44'',',
'       age_35_44 / (age_under_16 + age_16_24 + age_25_34 + age_35_44 + age_45_54 + age_55_64 + age_65_over)',
'FROM shelter_system_flow',
'WHERE flow_date = TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD'')',
'  AND population_group = ''All Population''',
'UNION ALL',
'SELECT 5, ''45-54'',',
'       age_45_54 / (age_under_16 + age_16_24 + age_25_34 + age_35_44 + age_45_54 + age_55_64 + age_65_over)',
'FROM shelter_system_flow',
'WHERE flow_date = TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD'')',
'  AND population_group = ''All Population''',
'UNION ALL',
'SELECT 6, ''55-64'',',
'       age_55_64 / (age_under_16 + age_16_24 + age_25_34 + age_35_44 + age_45_54 + age_55_64 + age_65_over)',
'FROM shelter_system_flow',
'WHERE flow_date = TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD'')',
'  AND population_group = ''All Population''',
'UNION ALL',
'SELECT 7, ''65+'',',
'       age_65_over / (age_under_16 + age_16_24 + age_25_34 + age_35_44 + age_45_54 + age_55_64 + age_65_over)',
'FROM shelter_system_flow',
'WHERE flow_date = TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD'')',
'  AND population_group = ''All Population''',
'ORDER BY sort_order'))
,p_ajax_items_to_submit=>'P2_REPORTING_DATE'
,p_items_value_column_name=>'PCT'
,p_group_short_desc_column_name=>'PCT'
,p_items_label_column_name=>'AGE_BAND'
,p_color=>'#ff9500'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>true
,p_items_label_position=>'center'
,p_items_label_display_as=>'PERCENT'
,p_items_label_font_family=>'Arial'
,p_items_label_font_size=>'22'
,p_items_label_font_color=>'#f5f5f5'
,p_threshold_display=>'onIndicator'
);
