wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(161360253803071784125)
,p_plug_name=>'Monthly KPIs'
,p_region_template_options=>'#DEFAULT#:t-CardsRegion--hideHeader js-addHiddenHeadingRoleDesc'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2072724515482255512
,p_plug_display_sequence=>40
,p_plug_grid_column_span=>12
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT 1 AS sort_order,',
'       ''Shelter System Inflow'' AS kpi_label,',
'       TO_CHAR(newly_identified + returned_from_housing + returned_to_shelter,',
'               ''FM999G999G990'') AS kpi_value,',
'       ''#FBE4EB'' AS bg_color,',
'       ''#C2185B'' AS text_color',
'FROM shelter_system_flow',
'WHERE flow_date = TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD'')',
'  AND population_group = ''All Population''',
'UNION ALL',
'SELECT 2,',
'       ''Change (Inflow - Outflow)'',',
'       TO_CHAR((newly_identified + returned_from_housing + returned_to_shelter)',
'                 - (moved_to_housing + became_inactive),',
'               ''FMS999G999G990''),',
'       CASE',
'         WHEN (newly_identified + returned_from_housing + returned_to_shelter)',
'              - (moved_to_housing + became_inactive) > 0 THEN ''#FFEBEE''',
'         WHEN (newly_identified + returned_from_housing + returned_to_shelter)',
'              - (moved_to_housing + became_inactive) < 0 THEN ''#E8F5E9''',
'         ELSE ''#E8E8E8''',
'       END,',
'       CASE',
'         WHEN (newly_identified + returned_from_housing + returned_to_shelter)',
'              - (moved_to_housing + became_inactive) > 0 THEN ''#C62828''',
'         WHEN (newly_identified + returned_from_housing + returned_to_shelter)',
'              - (moved_to_housing + became_inactive) < 0 THEN ''#2E7D32''',
'         ELSE ''#333333''',
'       END',
'FROM shelter_system_flow',
'WHERE flow_date = TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD'')',
'  AND population_group = ''All Population''',
'UNION ALL',
'SELECT 3,',
'       ''Shelter System Outflow'',',
'       TO_CHAR(moved_to_housing + became_inactive, ''FM999G999G990''),',
'       ''#E8F5E9'',',
'       ''#2E7D32''',
'FROM shelter_system_flow',
'WHERE flow_date = TO_DATE(:P2_REPORTING_DATE, ''YYYY-MM-DD'')',
'  AND population_group = ''All Population''',
'ORDER BY sort_order'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_CARDS'
,p_ajax_items_to_submit=>'P2_REPORTING_DATE'
,p_plug_query_num_rows_type=>'SCROLL'
,p_show_total_row_count=>false
);
