wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(12097740735545227)
,p_chart_id=>wwv_flow_imp.id(12097642065545226)
,p_seq=>10
,p_name=>'New'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT flow_date, TO_CHAR(flow_date, ''YYYY-MM'') AS month_label,',
'       ''Inflow - Newly Identified'' AS flow_type,',
'       newly_identified AS flow_value,',
'       ''#E63946'' AS color_val',
'FROM shelter_system_flow',
'WHERE population_group = :P3_POPULATION_GROUP',
'  AND (:P3_YEAR = ''All'' OR EXTRACT(YEAR FROM flow_date) = TO_NUMBER(:P3_YEAR))',
'  AND (:P3_MONTH = ''All'' OR EXTRACT(MONTH FROM flow_date) = TO_NUMBER(:P3_MONTH))',
'UNION ALL',
'SELECT flow_date, TO_CHAR(flow_date, ''YYYY-MM''),',
'       ''Inflow - Returned from Permanent Housing'',',
'       returned_from_housing,',
'       ''#FFD600''',
'FROM shelter_system_flow',
'WHERE population_group = :P3_POPULATION_GROUP',
'  AND (:P3_YEAR = ''All'' OR EXTRACT(YEAR FROM flow_date) = TO_NUMBER(:P3_YEAR))',
'  AND (:P3_MONTH = ''All'' OR EXTRACT(MONTH FROM flow_date) = TO_NUMBER(:P3_MONTH))',
'UNION ALL',
'SELECT flow_date, TO_CHAR(flow_date, ''YYYY-MM''),',
'       ''Inflow - Returned to Shelter'',',
'       returned_to_shelter,',
'       ''#FB8C00''',
'FROM shelter_system_flow',
'WHERE population_group = :P3_POPULATION_GROUP',
'  AND (:P3_YEAR = ''All'' OR EXTRACT(YEAR FROM flow_date) = TO_NUMBER(:P3_YEAR))',
'  AND (:P3_MONTH = ''All'' OR EXTRACT(MONTH FROM flow_date) = TO_NUMBER(:P3_MONTH))',
'UNION ALL',
'SELECT flow_date, TO_CHAR(flow_date, ''YYYY-MM''),',
'       ''Outflow - Became Inactive'',',
'       -1 * became_inactive,',
'       ''#512DA8''',
'FROM shelter_system_flow',
'WHERE population_group = :P3_POPULATION_GROUP',
'  AND (:P3_YEAR = ''All'' OR EXTRACT(YEAR FROM flow_date) = TO_NUMBER(:P3_YEAR))',
'  AND (:P3_MONTH = ''All'' OR EXTRACT(MONTH FROM flow_date) = TO_NUMBER(:P3_MONTH))',
'UNION ALL',
'SELECT flow_date, TO_CHAR(flow_date, ''YYYY-MM''),',
'       ''Outflow - Moved to Permanent Housing'',',
'       -1 * moved_to_housing,',
'       ''#66CC66''',
'FROM shelter_system_flow',
'WHERE population_group = :P3_POPULATION_GROUP',
'  AND (:P3_YEAR = ''All'' OR EXTRACT(YEAR FROM flow_date) = TO_NUMBER(:P3_YEAR))',
'  AND (:P3_MONTH = ''All'' OR EXTRACT(MONTH FROM flow_date) = TO_NUMBER(:P3_MONTH))',
'ORDER BY 1, 3'))
,p_ajax_items_to_submit=>'P3_POPULATION_GROUP,P3_YEAR,P3_MONTH'
,p_series_name_column_name=>'FLOW_TYPE'
,p_items_value_column_name=>'FLOW_VALUE'
,p_items_label_column_name=>'MONTH_LABEL'
,p_color=>'&COLOR_VAL.'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>false
);
